import "./alert-dialog.css";

import { AlertDialog } from "radix-ui";

import { AlertDialogContext } from "./alert-dialog.context";
import { alertDialogVariants } from "./alert-dialog.variants";

export type AlertDialogRootProps = React.ComponentProps<typeof AlertDialog.Root>;

export const AlertDialogRoot = (props: AlertDialogRootProps) => {
  const slots = alertDialogVariants();

  return (
    <AlertDialogContext value={{ slots }}>
      <AlertDialog.Root {...props} />
    </AlertDialogContext>
  );
};

import { AlertDialog } from "radix-ui";

export type AlertDialogTriggerProps = React.ComponentProps<typeof AlertDialog.Trigger>;

export const AlertDialogTrigger = (props: AlertDialogTriggerProps) => {
  return <AlertDialog.Trigger asChild {...props} />;
};

import { AlertDialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAlertDialogContext } from "./alert-dialog.context";

export type AlertDialogContentProps = React.ComponentProps<typeof AlertDialog.Content>;

export const AlertDialogContent = ({ children, className, ...props }: AlertDialogContentProps) => {
  const { slots } = useAlertDialogContext();

  return (
    <AlertDialog.Portal>
      <AlertDialog.Overlay className={slots.overlay()} />
      <AlertDialog.Content className={cn(slots.content(), className)} {...props}>
        {children}
      </AlertDialog.Content>
    </AlertDialog.Portal>
  );
};

import { AlertDialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAlertDialogContext } from "./alert-dialog.context";

