import { createContext, useContext } from "react";

import { alertDialogVariants } from "./alert-dialog.variants";

export type AlertDialogContext = {
  slots: ReturnType<typeof alertDialogVariants>;
};

export const AlertDialogContext = createContext<AlertDialogContext | null>(null);

export const useAlertDialogContext = () => {
  const context = useContext(AlertDialogContext);
  if (!context) {
    throw new Error("useAlertDialogContext must be used within an AlertDialog");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const alertDialogVariants = tv({
  slots: {
    overlay: "alert-dialog__overlay",
    content: "alert-dialog__content",
    title: "alert-dialog__title",
    description: "alert-dialog__description",
    actions: "alert-dialog__actions",
    cancel: "alert-dialog__cancel",
    action: "alert-dialog__action",
  },
});

export type AlertDialogVariants = VariantProps<typeof alertDialogVariants>;

.alert-dialog__overlay {
  @apply fixed inset-0 z-50 bg-black/80;

  &[data-state="open"] {
    @apply animate-in fade-in-0;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0;
  }
}

.alert-dialog__content {
  @apply bg-background fixed top-1/2 left-1/2 z-50 grid w-full max-w-lg -translate-x-1/2 -translate-y-1/2 gap-4 rounded-lg border p-6 shadow-lg duration-200;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95 slide-in-from-left-1/2 slide-in-from-top-[48%];
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95 slide-out-to-left-1/2 slide-out-to-top-[48%];
  }
}

.alert-dialog__title {
  @apply text-lg font-semibold;
}

.alert-dialog__description {
  @apply text-muted-foreground text-sm;
}

.alert-dialog__actions {
  @apply flex flex-col-reverse gap-2 sm:flex-row sm:justify-end;
}

.alert-dialog__cancel {
  @apply border-input bg-background inline-flex h-9 items-center justify-center rounded-md border px-4 text-sm font-medium transition-colors;

  &:hover {
    @apply bg-accent text-accent-foreground;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

.alert-dialog__action {
  @apply bg-destructive text-primary-foreground inline-flex h-9 items-center justify-center rounded-md px-4 text-sm font-medium transition-colors;

  &:hover {
    @apply bg-destructive/90;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

import { AlertDialogAction } from "./alert-dialog-action";
import { AlertDialogCancel } from "./alert-dialog-cancel";
import { AlertDialogContent } from "./alert-dialog-content";
import { AlertDialogDescription } from "./alert-dialog-description";
import { AlertDialogRoot } from "./alert-dialog-root";
import { AlertDialogTitle } from "./alert-dialog-title";
import { AlertDialogTrigger } from "./alert-dialog-trigger";

export const AlertDialog = {
  Action: AlertDialogAction,
  Cancel: AlertDialogCancel,
  Content: AlertDialogContent,
  Description: AlertDialogDescription,
  Root: AlertDialogRoot,
  Title: AlertDialogTitle,
  Trigger: AlertDialogTrigger,
};

export {
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogRoot,
  AlertDialogTitle,
  AlertDialogTrigger,
};

export { AlertDialogContext, useAlertDialogContext } from "./alert-dialog.context";

export { type AlertDialogVariants, alertDialogVariants } from "./alert-dialog.variants";
